using VisionaryCoder.Generators.Domain;
using Xunit;

namespace vc.Generators.Tests; public sealed class EventGeneratorTests { private static ImmutableArray<SyntaxTree> GetCompilation(string source, string attributeSource) =>
    [CSharpSyntaxTree.ParseText(text: attributeSource), CSharpSyntaxTree.ParseText(text: source)]; private static Compilation CreateCompilation(ImmutableArray<SyntaxTree> trees) { var references = AppDomain.CurrentDomain.GetAssemblies().Where(predicate: a => !a.IsDynamic && a.Location.Length > 0).Select(selector: a => MetadataReference.CreateFromFile(path: a.Location)).Distinct().ToArray(); return CSharpCompilation.Create(assemblyName: "GeneratorTest").AddReferences(references: references).AddSyntaxTrees(trees: trees); } private static (Compilation, IEnumerable<string>) RunGenerator(string source, string attributeSource = "") { var defaultAttribute = "namespace VisionaryCoder.Tooling.Shared.Attributes; [AttributeUsage(AttributeTargets.Class)] public sealed class DomainEventAttribute : Attribute {}"; var attr = string.IsNullOrEmpty(value: attributeSource) ? defaultAttribute : attributeSource; var trees = GetCompilation(source: source, attributeSource: attr); var compilation = CreateCompilation(trees: trees); var generator = new EventGenerator(); var driver = CSharpGeneratorDriver.Create(incrementalGenerators: generator); driver.RunGeneratorsAndUpdateCompilation(compilation: compilation, outputCompilation: out var outputCompilation, diagnostics: out _); var sources = outputCompilation.SyntaxTrees.Skip(count: compilation.SyntaxTrees.Count()).Select(selector: st => st.GetText().ToString()).ToList(); return (outputCompilation, sources); } [Fact] public void GeneratorExecutes() { var (_, s) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.True(condition: true); } [Fact] public void ProducesOutput() { var (_, s) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.NotEmpty(collection: s); } [Fact] public void ContainsEnvelopeRecord() { var (_, s) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains(expectedSubstring: "record", actualString: s.First()); } [Fact] public void ContainsCorrelationId() { var (_, s) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains(expectedSubstring: "CorrelationId", actualString: s.First()); } [Fact] public void ContainsCausationId() { var (_, s) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains(expectedSubstring: "CausationId", actualString: s.First()); } [Fact] public void ContainsTimestamp() { var (_, s) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains(expectedSubstring: "Timestamp", actualString: s.First()); } [Fact] public void ContainsCreateFactory() { var (_, s) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains(expectedSubstring: "Create", actualString: s.First()); } [Fact] public void ContainsAutoGenHeader() { var (_, s) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains(expectedSubstring: "auto-generated", actualString: s.First()); } [Fact] public void ContainsNullableDirective() { var (_, s) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Contains(expectedSubstring: "#nullable", actualString: s.First()); } [Fact] public void IsDeterministic() { var (_, s1) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); var (_, s2) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events; [DomainEvent] public class UserCreated {}"); Assert.Equal(expected: s1.First(), actual: s2.First()); } [Fact] public void PreservesNamespace() { var (_, s) = RunGenerator(source: "using VisionaryCoder.Tooling.Shared.Attributes; namespace Events.Orders; [DomainEvent] public class OrderCreated {}"); Assert.Contains(expectedSubstring: "namespace Events.Orders", actualString: s.First()); } }
